export const cfActivities: Activity[] = [
  {"id":"cf-marker-bleed-butterflies","title":"Marker-Bleed Butterflies","altNames":["Coffee Filter Butterflies","Tie-Dye Butterflies","Spray Butterflies"],"type":"Craft","place":"Both","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Scribble, spritz, and watch the colors bloom into a clothespin butterfly that flutters.","materials":["Coffee filters, 1-2 per camper","Washable markers, assorted colors","Spray bottle of water (or cups of water with droppers)","Clothespins, 1 per camper","Pipe cleaners, 1 per camper","Paper towels to dry on","Scissors"],"materialTags":["Coffee filters","Markers","Water source","Clothespins","Pipe cleaners","Paper towels","Scissors"],"steps":["Lay a flat coffee filter on a paper towel and color it boldly with washable markers — solid blocks and rings bleed best.","Lightly mist the filter with the spray bottle until the marker starts to spread, then stop before it turns to mush.","Set the wet filter on a dry paper towel and let it dry for several minutes (a sunny windowsill speeds it up).","Pinch the dry filter in the middle and accordion-fold it, or scrunch it, to make wings.","Clip a clothespin over the pinched middle to form the body, then twist a pipe cleaner around the clothespin head for antennae.","Bend the antennae into curls and fan the wings out so the butterfly stands or hangs."],"notes":"Run color-and-spray as the first half and assembly after a drying break so wet filters aren't rushed. Heavy marker coverage gives the richest bleed, so encourage filling the whole filter. For g79/g1012, challenge them to plan a symmetrical color map across both wings or layer two filters for a bigger moth.","safety":"Use only washable markers and keep the spray bottle on a fine mist so water isn't sprayed toward faces or eyes.","ages":["g13","g46","g79"],"rating":5,"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Skip the spray bottle and dab the filter with a wet sponge for a softer, more controlled bleed.","Clip two filters together for a layered four-wing butterfly with double the color.","Older campers design a matched left/right color pattern and grade each other on symmetry, then photograph the whole flutter together.","Tie a length of yarn to the antennae and hang the butterflies as a window garland."],"subsets":[["Pick 3-4 colors and color in big solid patches, not thin lines.","Press a little harder near the center where the body will be."],["Hold the bottle about a foot away and mist a few pumps.","Watch for colors touching and blending, then stop."],[],["Pinch a vertical line down the middle.","Fold back and forth like a paper fan."],["Open the clothespin and clamp the pinched center.","Wrap the pipe cleaner once around and leave two ends sticking up."],[]]},
  {"id":"cf-suncatchers","title":"Coffee Filter Suncatchers","altNames":["Stained Glass Filters","Window Suncatchers","Filter Sun Discs"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Glowing stained-glass circles that catch the sun in any sunny window.","materials":["Coffee filters, 1 per camper","Washable markers","Spray bottle of water","Cardboard ring or paper-plate frames","Glue","Scissors","Yarn for hanging","Hole punch","Paper towels"],"materialTags":["Coffee filters","Markers","Water source","Cardboard","Glue","Scissors","Yarn","Paper towels"],"steps":["Color a coffee filter all over with washable markers, leaving no big white gaps.","Mist the filter with water so the colors blend into a stained-glass wash, then dry on a paper towel.","While it dries, cut a frame: a cardboard ring or the center cut out of a paper plate.","Glue the dry filter behind the frame so the color shows through the opening.","Trim the excess filter around the frame edge for a clean circle.","Punch a hole at the top, thread yarn through, and tie a loop to hang in a window."],"notes":"Set drying filters in one spot and have campers cut frames during the wait so there's no idle time. Filters dry translucent, so a backlit window shows the colors best. For older grades, hand out a real frame shape (hexagon, leaf, fish silhouette) cut from cardboard to make a themed window panel.","safety":"Supervise scissors when cutting frame openings and trimming, and keep wet filters off electrical outlets and sills with cords.","ages":["g13","g46","g79"],"rating":5,"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Cut the dry filter into a shape (heart, star, leaf) and glue it directly to a window with a dab of glue stick.","Layer two filters of different color schemes for a deeper, richer suncatcher.","Older campers cut an intricate frame shape from cardboard and assemble a multi-panel window mural together.","Sprinkle a pinch of salt on the wet filter to create speckled crystal patterns as it dries."],"subsets":[["Cover the whole circle, edge to edge.","Mix warm and cool colors next to each other."],[],["Trace a cup or jar lid for a round opening.","Cut just inside the line for a clean ring."],[],[],["Punch the hole through the frame, not the thin filter.","Tie a loop big enough to slip over a hook."]]},
  {"id":"cf-dip-dye-flowers","title":"Dip-Dye Filter Flowers","altNames":["Coffee Filter Flowers","Dip-Dye Blooms","Filter Carnations"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Folded filters dipped corner-by-corner bloom into a bouquet of ombre flowers.","materials":["Coffee filters, 2-3 per camper","Cups of water tinted with washable marker or food coloring","Pipe cleaners, 1 per flower (green if available)","Paper towels","Scissors","Optional: green markers for leaves"],"materialTags":["Coffee filters","Markers","Water source","Pipe cleaners","Paper towels","Scissors"],"steps":["Make dye cups by scribbling washable marker heavily inside cups and adding a splash of water, one color per cup.","Fold a coffee filter in half, then half again, and again, into a small pie wedge.","Dip each corner and edge of the wedge into a different dye cup for just a second so the color wicks in.","Gently unfold the damp filter and set it on a paper towel to dry, repeating for 2-3 filters.","Stack the dry filters, pinch the center, and twist a pipe cleaner stem around the pinch.","Fluff and separate the layers upward into petals to open the bloom."],"notes":"Pre-mix dye cups so dipping moves fast and stays tidy; one cup per two campers keeps the table calm. Dipping only briefly is the trick — soaked filters tear, so coach a quick touch. For g79/g1012, have them build a full mixed bouquet with varied fold counts and ombre transitions, then arrange it in a decorated paper cup vase.","safety":"Keep dye cups in the center of the table to avoid spills and dye stains, and supervise scissors used to trim stems or petal edges.","ages":["g13","g46","g79"],"rating":4,"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Skip dipping and color the folded wedge directly with markers, then spritz to bleed for a faster version.","Bundle several finished flowers with a yarn-wrapped stem into a single bouquet to gift.","Older campers create a precise three-color ombre by controlling dip depth and folding into 16 layers for fuller petals.","Add a small pony-bead center threaded onto the stem before twisting for a flower with a button middle."],"subsets":[["Scribble until the cup bottom is fully colored.","Add only enough water to dissolve the ink."],["Crease each fold sharply.","End with a narrow triangle wedge."],["Touch the tip in for one second only.","Use a different color for each corner."],[],["Stack filters with centers lined up.","Twist the stem tight so layers don't slide."],[]]},
  {"id":"cf-coffee-filter-jellyfish","title":"Coffee Filter Jellyfish","altNames":["Under the Sea Jellyfish","Filter Jellies","Hanging Jellyfish"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"A bleed-dyed dome with curling streamer tentacles for an Under-the-Sea wall.","materials":["Coffee filters, 1 per camper","Washable markers (blues, purples, pinks)","Spray bottle of water","Yarn or thin streamers cut from filters, 6-8 per camper","Glue or masking tape","Scissors","Pony beads for googly eyes (optional)","Yarn for hanging","Paper towels"],"materialTags":["Coffee filters","Markers","Water source","Yarn","Glue","Scissors","Pony beads","Paper towels"],"steps":["Color a coffee filter in ocean tones, then mist with water to blend and dry it on a paper towel.","Cut 6-8 lengths of yarn or thin filter strips for the trailing tentacles.","Pinch or lightly stuff the dry filter into a rounded bell shape (a crumpled paper-towel ball inside helps).","Gather the bottom of the bell and glue or tape the tentacles around the inside rim.","Add two pony-bead or paper eyes to the front of the bell.","Tie a yarn loop to the top of the bell and hang it so the tentacles dangle."],"notes":"Pairs perfectly with an Under-the-Sea theme day; cluster finished jellies on a wall with coffee-filter fish. Curling the tentacles over a scissor blade or pencil gives them bounce. For older grades, have them build a graduated school — large bells to tiny ones — and string them at staggered heights for a hanging mobile.","safety":"Supervise scissors for cutting tentacles, and keep small pony beads away from any younger siblings or visitors in the room.","ages":["g13","g46","g79"],"rating":4,"links":[{"label":"S&S Blog: top summer camp themes","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Use only filter-strip tentacles (no yarn) and curl them over a pencil for an all-paper jellyfish.","Glue a cotton-ball-style scrunch of extra filter inside the bell for a puffier dome.","Older campers build a tiered mobile of five different-sized jellyfish balanced on a cardboard cross-bar.","Draw glow-pattern dots on the bell with marker before spraying to mimic a bioluminescent jelly."],"subsets":[[],["Cut strips about a hand-length long.","Mix yarn and filter strips for variety."],["Round the top, leave the bottom open.","Don't crush it flat — keep the dome."],["Space the tentacles evenly around the rim.","Press glue spots and hold a few seconds."],[],[]]},
  {"id":"cf-chromatography-art","title":"Filter Chromatography Art","altNames":["Color-Mixing Filters","Marker Chromatography","Color Separation Lab"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Watch a single marker dot crawl up a filter and split into the hidden colors that make it.","materials":["Coffee filters, 1-2 per camper","Washable markers, especially black/brown/green","Cups of water","Pencils or straws to suspend strips","Masking tape","Scissors","Paper towels","Ruler (optional)"],"materialTags":["Coffee filters","Markers","Water source","Straws","Masking tape","Scissors","Paper towels"],"steps":["Cut a coffee filter into strips about two fingers wide.","Draw a thick marker dot or line about an inch up from the bottom of each strip, one marker color per strip.","Tape the top of each strip to a pencil or straw laid across a cup.","Lower the strips so only the very bottom (below the ink) touches the water — the ink must stay dry.","Watch as water climbs the filter and carries the ink upward, separating it into bands of color.","Lift the strips out once colors stop climbing and dry them flat as a record of what each marker is made of."],"notes":"This is the science-forward filter craft — frame it as a real lab and have campers predict which colors hide inside black before they test it. The ink line must sit above the waterline or it dissolves into the cup. For g79/g1012, turn it into a controlled experiment: label strips, compare brands of black marker, and chart which separates into the most colors.","safety":"Use only washable (water-soluble) markers — permanent markers won't separate and involve solvents you don't want here.","ages":["g46","g79","g1012"],"rating":5,"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Use a round filter with a marker dot in the center and drip water on the dot to make color rings spread outward.","Race two markers side by side and see whose pigments climb fastest and farthest.","Older campers measure how high each color band rises in centimeters and rank the markers by number of separated pigments.","Mount the finished strips on a poster as a 'pigment fingerprint' display for each marker tested."],"subsets":[["Cut strips long enough to span the cup.","Keep widths even so they hang straight."],["Press the marker so the dot is dark.","Make sure the dot is an inch up, not at the very edge."],[],["Add just an inch of water to the cup.","Check that the ink line stays above the water."],["Be patient — it takes a few minutes.","Look for black splitting into blue, purple, and pink."],[]]},
  {"id":"cf-filter-dreamcatcher","title":"Filter Dreamcatcher","altNames":["Coffee Filter Dreamcatcher","Web Catcher","Filter Hoop Catcher"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"A bleed-dyed filter webbed with yarn and trailing beaded tails on a cardboard hoop.","materials":["Coffee filters, 1 per camper","Washable markers","Spray bottle of water","Cardboard rings (cut from cardboard or paper plates), 1 per camper","Yarn, 1-2 colors per camper","Pony beads, 6-10 per camper","Hole punch","Glue","Scissors","Paper towels"],"materialTags":["Coffee filters","Markers","Water source","Cardboard","Yarn","Pony beads","Glue","Scissors","Paper towels"],"steps":["Color and spray a coffee filter, then dry it while you prep the hoop.","Cut a cardboard ring (or remove the center of a paper plate) to serve as the hoop, and punch holes evenly around the inside.","Glue or stretch the dry dyed filter across the back of the hoop as a colored backing.","Lace yarn back and forth through the punched holes to weave a web across the hoop.","Cut three lengths of yarn for tails, tie them to the bottom of the hoop, and thread pony beads onto each.","Tie a yarn loop at the top and knot the bead ends so they don't slide off."],"notes":"Pre-cut and pre-punch the cardboard hoops to keep this within one session; the weaving is the part worth the time. The web is forgiving — any crisscross pattern looks good, so let campers freestyle. For g79/g1012, teach a real repeating loop-stitch web and have them plan a symmetric pattern and a balanced bead layout on the tails.","safety":"Supervise scissors and the hole punch, and remind campers not to pull yarn so tight that the cardboard hoop bends or snaps.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Skip the yarn web and just leave the dyed filter as a colored center for a faster younger-camper version.","Use two yarn colors and alternate them through the holes for a two-tone web.","Older campers weave a proper spiraling loop-stitch web from the rim toward a center point and add feathers cut from extra filters.","Add a small dyed-filter flower (from the dip-dye method) glued to the center of the web."],"subsets":[[],["Trace a bowl for the ring, then cut inside and out.","Punch 8-10 evenly spaced holes."],["Trim the filter to overhang the hoop slightly.","Glue around the rim and press flat."],["Start at one hole and cross to a far one.","Keep going around until a web forms."],["Tie tails at the 5, 6, and 7 o'clock spots.","Slide on a few beads per tail."],[]]},
  {"id":"cf-filter-wreath","title":"Coffee Filter Wreath","altNames":["Filter Flower Wreath","Paper Plate Wreath","Ruffle Wreath"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Dozens of scrunched dyed filters layered into a full, ruffly door wreath.","materials":["Coffee filters, 12-20 per camper","Washable markers or pre-tinted dye cups","Spray bottle of water","Paper plates with center cut out (wreath base), 1 per camper","Glue","Scissors","Yarn for hanging","Paper towels","Optional: foam-sheet leaves"],"materialTags":["Coffee filters","Markers","Water source","Paper plates","Glue","Scissors","Yarn","Paper towels","Foam sheets"],"steps":["Color and spray a big batch of coffee filters in your wreath's color scheme and let them dry.","Cut the center out of a paper plate to make a ring-shaped wreath base.","Pinch the center of each dry filter and scrunch it into a ruffly rosette.","Glue the scrunched filters tightly side by side all around the ring so no plate shows.","Add a second layer of filters in the gaps to make the wreath full and dense.","Tie a yarn loop to the back and add foam-sheet leaves or a paper bow if you like."],"notes":"This is a big-batch craft — dyeing 15+ filters per camper is the bulk of the time, so run the dye step the day before or as a group station. Density is everything; a packed wreath looks far better than a sparse one. For g79/g1012, assign a color gradient around the ring or have them collaborate on one large team wreath for the cabin door.","safety":"Supervise scissors for cutting plate centers, and run the glue stations on covered tables since this craft uses a lot of glue.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make a single-color wreath with white filters for a clean, simple look that's faster to assemble.","Use a cardboard ring instead of a paper plate for a sturdier base on a heavier wreath.","Older campers design a full color-gradient that fades around the ring and add a hand-lettered cabin name to the center.","Glue a few dip-dye flowers and foam butterflies onto the finished wreath as accents."],"subsets":[["Aim for at least a dozen filters per wreath.","Use 2-3 related colors for depth."],["Trace a cup in the center and cut it out.","Leave a ring about two fingers wide."],["Pinch dead center and twist.","Keep the ruffles facing up and out."],["Start on the outer edge and work in.","Press each filter so the glue grabs."],[],[]]},
  {"id":"cf-tie-dye-filter-rounds","title":"Tie-Dye Filter Rounds","altNames":["Folded Filter Tie-Dye","Filter Mandalas","Tie-Dye Discs"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Fold, dot, and spritz a filter into a kaleidoscope tie-dye round — no fabric, no mess kit.","materials":["Coffee filters, 2 per camper","Washable markers","Spray bottle of water","Paper towels","Scissors (optional)","Tape or glue to mount finished rounds"],"materialTags":["Coffee filters","Markers","Water source","Paper towels","Scissors","Masking tape"],"steps":["Fold a coffee filter into a small wedge (in half, half, and half again).","Color the folded wedge with bands and dots of marker along the edges and point.","Lightly mist the folded wedge so the color soaks through all the layers.","Carefully unfold the damp filter to reveal a symmetrical mandala pattern.","Lay it flat on a paper towel to dry, then make a second with a different fold or palette.","Mount the dry rounds on a window or a backing card, or string several into a banner."],"notes":"The fast, low-prep cousin of fabric tie-dye — great as a filler or a calm-down craft. The reveal moment when they unfold is the hook, so let them do it slowly. For older grades, teach different fold counts (4, 8, 16 layers) and have them predict how the symmetry changes, then compare results across the table.","safety":"Mist gently and unfold wet filters slowly so they don't tear, and keep washable markers off skin and clothing.","ages":["g13","g46","g79"],"rating":4,"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Color the wedge in only warm or only cool colors for a themed monochrome round.","Spritz with very tinted water (marker-dyed) instead of plain water for a deeper saturated dye.","Older campers fold to 16 layers and design an intentional repeating motif that mirrors perfectly when unfolded.","String a line of finished rounds with yarn for a tie-dye bunting across the cabin."],"subsets":[["Crease each fold flat and sharp.","Make it small so colors reach the center."],["Add dots near the point for a center burst.","Stripe the curved edge for outer rings."],[],["Peel layers apart gently while damp.","Open from the point outward."],[],[]]},
  {"id":"cf-filter-parachutes","title":"Filter Parachutes","altNames":["Coffee Filter Parachute","Drop-Test Chutes","Filter Skydiver"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Build a coffee-filter parachute, then drop-test it to engineer the slowest, smoothest fall.","materials":["Coffee filters, 2-3 per camper","Yarn or string cut into equal lengths","Masking tape","Small weights (a pony bead, washer, or rolled tape ball)","Scissors","Hole punch","Markers to decorate","A stairwell, balcony, or stable chair to drop from"],"materialTags":["Coffee filters","Yarn","Masking tape","Pony beads","Scissors","Markers"],"steps":["Punch or poke four evenly spaced holes around the rim of a coffee filter.","Cut four equal lengths of yarn and tie one through each hole.","Gather the four free ends together and tie them to a small weight (a pony bead or a tape ball).","Decorate the canopy with markers and give your skydiver a name.","Hold the canopy up by the center and drop it from a safe height, watching how slowly it falls.","Time the fall, then tweak the design — bigger canopy, lighter weight, longer strings — and test again."],"notes":"Frame this as a mini engineering challenge: slowest fall wins. Equal string lengths are the single biggest factor in a stable, non-tumbling chute. For g79/g1012, run controlled trials changing one variable at a time (canopy size, vent hole in the center, weight) and chart fall times to find the optimal design.","safety":"Drop only from a counselor-approved safe height with a clear landing zone — no climbing on railings, furniture, or out of windows.","ages":["g46","g79","g1012"],"rating":5,"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Race two parachutes dropped at the same moment and see whose floats longest.","Cut a small hole in the center of the canopy and test whether the vent makes it fall straighter.","Older campers run a single-variable experiment (weight, canopy size, or string length), record fall times, and present the optimal build.","Build a double-canopy parachute by stacking two filters and compare it to a single."],"subsets":[["Space holes like 12, 3, 6, and 9 on a clock.","Reinforce each hole with a small tape square first."],["Cut all four strings the exact same length.","Tie a sturdy knot at each hole."],["Line up all four ends evenly.","Knot them around the weight so it hangs centered."],[],[],["Change only one thing at a time.","Drop from the same spot each test."]]},
  {"id":"cf-filter-doves","title":"Coffee Filter Doves","altNames":["Filter Birds","Peace Doves","Clothespin Doves"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"A folded filter clipped into a winged bird that hangs and spins on a string.","materials":["Coffee filters, 1-2 per camper","Washable markers (optional, for color)","Clothespins, 1 per camper","Pony beads or paper for eyes","Glue","Scissors","Yarn for hanging","Spray bottle (optional)"],"materialTags":["Coffee filters","Markers","Clothespins","Pony beads","Glue","Scissors","Yarn"],"steps":["Leave a filter white for a classic dove, or color and spritz it for a tropical bird, then dry.","Accordion-fold the filter back and forth into a fan to make the wings.","Pinch the fan in the middle and clip a clothespin over it to form the body.","Round or pinch one end of a small filter scrap into a head and beak, and glue it to the front of the clothespin.","Add a pony-bead or paper eye to each side of the head.","Fan out the wings, tie a yarn loop to the body, and hang the dove so it spins freely."],"notes":"Works as a calm craft or as a Kindness/Peace theme tie-in (white doves with written wishes on the wings). The clothespin grip means no drying-glue wait for the body. For older grades, have them shape a real bird silhouette — head, tail, and layered wings — and design a species (parrot, swallow) with accurate coloring.","safety":"Watch fingers around the clothespin spring when clamping, and supervise scissors used to shape heads and beaks.","ages":["g13","g46","g79"],"rating":3,"links":[{"label":"S&S Blog: top summer camp themes","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Write a kindness wish or a friend's name along each wing before folding for a Kindness Day version.","Make a second smaller filter into a tail fanned the opposite direction for a fuller bird.","Older campers craft a recognizable species with shaped tail feathers, layered wings, and accurate markings.","String several doves at different heights from a stick to make a flying-flock mobile."],"subsets":[[],["Keep folds about a finger-width wide.","Crease each one before the next."],["Clamp dead center of the fan.","Make sure both wings spread evenly."],["Cut a small teardrop for the head.","Glue it so a point sticks out as a beak."],[],[]]},
  {"id":"cf-layered-filter-mandalas","title":"Layered Filter Mandalas","altNames":["Filter Mandala Stack","Layered Suncatcher Mandala","Tissue-Style Filter Mandala"],"type":"Craft","place":"Inside","ageMin":12,"ageMax":18,"durationMin":60,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Stack three dyed, cut filters into a layered mandala medallion with depth and symmetry.","materials":["Coffee filters, 3 per camper","Washable markers","Spray bottle of water","Scissors","Glue","Cardboard or cardstock backing circle, 1 per camper","Hole punch and yarn (to hang)","Paper towels","Pencil for marking folds"],"materialTags":["Coffee filters","Markers","Water source","Scissors","Glue","Cardboard","Yarn","Paper towels"],"steps":["Color and spray three coffee filters in coordinating palettes (e.g. a warm, a cool, and a metallic-ish gold) and dry them.","Fold each dry filter into eighths and cut notches, points, and slits along the folded edges, kaleidoscope-style.","Unfold all three to reveal three different symmetrical cut patterns.","Glue the largest pattern to a backing circle, then layer the medium and smallest on top, rotating each so the cuts peek through.","Press the layers flat and let the glue set so the mandala holds together.","Punch a hole, add a yarn loop, and hang it where light passes through the cut openings."],"notes":"This is the most involved filter craft — pitched at older campers who want a real design challenge and the patience for precise cutting. The wow factor comes from rotating each cut layer so the patterns interlock. Push g1012 to plan a deliberate radial symmetry and a color-depth order (darkest back, lightest front) rather than cutting randomly.","safety":"Cutting folded filters takes firm, controlled scissor work — keep cutting hands clear of the holding hand and use blunt-tip scissors.","ages":["g79","g1012"],"rating":4,"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a simpler two-layer version with just one cut filter over a solid dyed backing for a shorter session.","Mount the finished mandala in a cardboard ring frame instead of a backing circle so light passes fully through.","Challenge g1012 to cut a true repeating eight-fold radial motif where every wedge is identical.","Build a set of three mandalas in a gradient and hang them as a vertical wall column."],"subsets":[["Pick three palettes that work together.","Make one filter clearly lighter for the top layer."],["Fold into eighths and crease hard.","Cut shapes into the folded edges, not all the way across."],["Open slowly to avoid tearing.","Flatten under a book if curled."],["Rotate each layer a little before gluing.","Glue only the centers so cut edges stay loose."],[],[]]},
  {"id":"cf-spinning-filter-tops","title":"Spinning Filter Tops","altNames":["Coffee Filter Spinners","Color-Blend Tops","Twirl Tops"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"A marker-striped filter on a straw axle that blurs its colors into new ones when it spins.","materials":["Coffee filters, 1-2 per camper","Washable markers","Straws cut short, or pencils, 1 per camper","Cardboard scrap for a stiffening disc (optional)","Masking tape","Scissors","Pony bead (optional, for a balanced tip)"],"materialTags":["Coffee filters","Markers","Straws","Cardboard","Masking tape","Scissors","Pony beads"],"steps":["Flatten a coffee filter and color it in bold pie-slice wedges or concentric rings (primary colors blend best).","For stiffness, glue or tape the filter onto a same-size cardboard disc, or layer two filters.","Poke a small hole in the exact center and push a short straw or pencil through as the spindle.","Tape the filter to the spindle so it sits perpendicular and centered (balance is key).","Spin the top hard on a flat surface and watch the colors blur and mix into new shades.","Re-color or re-balance and test which color combos make the cleanest blend (e.g. red+yellow looking orange)."],"notes":"A craft-meets-science spinner: it's both a color-mixing demo and a competitive spinning toy. Centering the spindle is what separates a wobbler from a true spinner, so coach precise center holes. For g79/g1012, challenge them to predict the spun color of each wedge layout and to engineer the longest-spinning, best-balanced top.","safety":"Poke center holes with a counselor-supervised pencil tip, not anything sharp, and keep spinning tops clear of faces and the table edge.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a Newton-style color wheel with all rainbow wedges and see if it blurs toward white-ish gray.","Hold spin-offs to see whose top spins the longest, then study why the winner balanced best.","Older campers calculate and lay out exact wedge angles, then predict each blended result before spinning.","Use a pony bead as a smooth pivot tip glued under the center for a longer, steadier spin."],"subsets":[["Use 3-4 colors max for clean mixing.","Keep wedges even in size."],["A cardboard disc keeps it from flopping.","Match the disc size to the filter."],["Find the center by folding in quarters first.","Make the hole just big enough for the straw."],["Check that the filter sits flat, not tilted.","Tape both sides of the spindle to lock it."],[],[]]},
];
